#!/usr/bin/env python

import os
import sys
import tarfile
import zipfile
import subprocess
import time
from datetime import datetime

def create_backup(source_dir, format_type='tar.gz'):
    if not os.path.exists(source_dir):
        print("Error: Source directory '{}' does not exist".format(source_dir))
        return False
    
    if not os.path.isdir(source_dir):
        print("Error: '{}' is not a directory".format(source_dir))
        return False
    
    timestamp = datetime.now().strftime('%Y%m%d_%H%M%S')
    base_name = os.path.basename(os.path.abspath(source_dir))
    backup_name = "{}_backup_{}".format(base_name, timestamp)
    
    format_type = format_type.lower()
    
    if format_type == 'tar.gz' or format_type == 'tgz':
        backup_file = backup_name + '.tar.gz'
        return create_tar_backup(source_dir, backup_file, 'gz')
    elif format_type == 'tar.bz2' or format_type == 'tbz2' or format_type == 'bz2':
        backup_file = backup_name + '.tar.bz2'
        return create_tar_backup(source_dir, backup_file, 'bz2')
    elif format_type == 'zip':
        backup_file = backup_name + '.zip'
        return create_zip_backup(source_dir, backup_file)
    elif format_type == '7z':
        backup_file = backup_name + '.7z'
        return create_7z_backup(source_dir, backup_file)
    else:
        print("Error: Unsupported format '{}'".format(format_type))
        print("Supported formats: tar.gz, tar.bz2, zip, 7z")
        return False

def create_tar_backup(source_dir, backup_file, compression):
    try:
        print("Creating {} backup of '{}'...".format(compression, source_dir))
        mode = 'w:' + compression
        with tarfile.open(backup_file, mode) as tar:
            tar.add(source_dir, arcname=os.path.basename(source_dir))
        print("Backup created successfully: {}".format(backup_file))
        print("Backup size: {} bytes".format(os.path.getsize(backup_file)))
        return True
    except Exception as e:
        print("Error creating tar backup: {}".format(str(e)))
        if os.path.exists(backup_file):
            os.remove(backup_file)
        return False

def create_zip_backup(source_dir, backup_file):
    try:
        print("Creating ZIP backup of '{}'...".format(source_dir))
        with zipfile.ZipFile(backup_file, 'w', zipfile.ZIP_DEFLATED) as zipf:
            for root, dirs, files in os.walk(source_dir):
                for file in files:
                    file_path = os.path.join(root, file)
                    arcname = os.path.relpath(file_path, os.path.dirname(source_dir))
                    zipf.write(file_path, arcname)
        print("Backup created successfully: {}".format(backup_file))
        print("Backup size: {} bytes".format(os.path.getsize(backup_file)))
        return True
    except Exception as e:
        print("Error creating ZIP backup: {}".format(str(e)))
        if os.path.exists(backup_file):
            os.remove(backup_file)
        return False

def create_7z_backup(source_dir, backup_file):
    try:
        print("Creating 7z backup of '{}'...".format(source_dir))
        seven_z = find_7z_executable()
        if not seven_z:
            print("Error: 7z executable not found")
            print("Please install p7zip or 7-zip")
            return False
        
        cmd = [seven_z, 'a', '-t7z', backup_file, source_dir]
        proc = subprocess.Popen(cmd, stdout=subprocess.PIPE, stderr=subprocess.PIPE)
        stdout, stderr = proc.communicate()
        
        if proc.returncode == 0:
            print("Backup created successfully: {}".format(backup_file))
            if os.path.exists(backup_file):
                print("Backup size: {} bytes".format(os.path.getsize(backup_file)))
            return True
        else:
            print("Error creating 7z backup:")
            if stderr:
                print(stderr.decode('utf-8', errors='ignore'))
            return False
    except Exception as e:
        print("Error creating 7z backup: {}".format(str(e)))
        if os.path.exists(backup_file):
            os.remove(backup_file)
        return False

def find_7z_executable():
    possible_names = ['7z', '7za', '7zr', 'p7zip']
    for name in possible_names:
        try:
            proc = subprocess.Popen([name], stdout=subprocess.PIPE, stderr=subprocess.PIPE)
            proc.communicate()
            return name
        except:
            continue
    return None

def print_usage():
    print("Usage: python backup.py <directory_path> [format]")
    print("")
    print("Arguments:")
    print("  directory_path  : Path to the directory to backup")
    print("  format          : Compression format (default: tar.gz)")
    print("")
    print("Supported formats:")
    print("  tar.gz, tgz     : Gzip compressed tar archive")
    print("  tar.bz2, tbz2   : Bzip2 compressed tar archive")
    print("  zip             : ZIP archive")
    print("  7z              : 7-Zip archive (requires 7z/p7zip installed)")
    print("")
    print("Examples:")
    print("  python backup.py /home/user/documents")
    print("  python backup.py /home/user/documents tar.bz2")
    print("  python backup.py /home/user/documents zip")

if __name__ == '__main__':
    if len(sys.argv) < 2:
        print_usage()
        sys.exit(1)
    
    source_directory = sys.argv[1]
    backup_format = 'tar.gz'
    
    if len(sys.argv) >= 3:
        backup_format = sys.argv[2]
    
    success = create_backup(source_directory, backup_format)
    sys.exit(0 if success else 1)